class Allocator:
    def __init__(self, n):
        self.n = n
        self.owner = {}

    def allocate(self, size, mID):
        n = self.n
        i = 0
        while i <= n - size:
            j = i
            while j < i + size and j not in self.owner:
                j += 1
            if j == i + size:
                for k in range(i, i + size):
                    self.owner[k] = mID
                return i
            i = j + 1
        return -1

    def freeMemory(self, mID):
        freed = [k for k, v in self.owner.items() if v == mID]
        for k in freed:
            del self.owner[k]
        return len(freed)

