class Allocator:
    def __init__(self, n):
        self.mem = [0] * n
        self.n = n

    def allocate(self, size, mID):
        n = self.n
        run = 0
        start = -1
        for i in range(n):
            if self.mem[i] == 0:
                if run == 0:
                    start = i
                run += 1
                if run == size:
                    for j in range(start, start + size):
                        self.mem[j] = mID
                    return start
            else:
                run = 0
                start = -1
        return -1

    def freeMemory(self, mID):
        freed = 0
        for i in range(self.n):
            if self.mem[i] == mID:
                self.mem[i] = 0
                freed += 1
        return freed

