class Allocator {
    constructor(n) {
        this.mem = new Array(n).fill(0);
        this.n = n;
    }

    allocate(size, mID) {
        const n = this.n;
        let run = 0;
        let start = -1;
        for (let i = 0; i < n; i++) {
            if (this.mem[i] === 0) {
                if (run === 0) start = i;
                run += 1;
                if (run === size) {
                    for (let j = start; j < start + size; j++) this.mem[j] = mID;
                    return start;
                }
            } else {
                run = 0;
                start = -1;
            }
        }
        return -1;
    }

    freeMemory(mID) {
        let freed = 0;
        for (let i = 0; i < this.n; i++) {
            if (this.mem[i] === mID) {
                this.mem[i] = 0;
                freed += 1;
            }
        }
        return freed;
    }
}
